#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#include "./../main.h"
#include "./../util/timer/timer.h"
#include "./kernel_cpu.h"

void kernel_cpu(par_str par,
                dim_str dim,
                box_str* box,
                FOUR_VECTOR* rv,
                fp* qv,
                FOUR_VECTOR* fv)
{
    long long time0, time1, time2, time3, time4, time5, time6;

    time0 = get_time();

    fp a2 = 2.0 * par.alpha * par.alpha;

    time1 = get_time();
    time2 = get_time();
    time3 = get_time();

    #pragma omp parallel for schedule(dynamic) num_threads(dim.cores_arg)
    for (int bx = 0; bx < dim.number_boxes; bx++) {

        // home box parameters
        int first_i = box[bx].offset;
        FOUR_VECTOR* rA = &rv[first_i];
        FOUR_VECTOR* fA = &fv[first_i];

        // local copy of rA
        FOUR_VECTOR rA_local[NUMBER_PAR_PER_BOX];
        for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
            rA_local[i] = rA[i];
        }

        // loop over neighbor boxes (including home box)
        for (int k = 0; k < (1 + box[bx].nn); k++) {

            int pointer;
            if (k == 0) {
                pointer = bx;
            } else {
                pointer = box[bx].nei[k-1].number;
            }

            int first_j = box[pointer].offset;
            FOUR_VECTOR* rB = &rv[first_j];
            fp* qB = &qv[first_j];

            // local copy of rB and qB
            FOUR_VECTOR rB_local[NUMBER_PAR_PER_BOX];
            fp qB_local[NUMBER_PAR_PER_BOX];
            for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                rB_local[j] = rB[j];
                qB_local[j] = qB[j];
            }

            // computation
            for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {

                fp fv_v = 0.0;
                fp fv_x = 0.0;
                fp fv_y = 0.0;
                fp fv_z = 0.0;

                for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {

                    fp r2 = (fp)rA_local[i].v + (fp)rB_local[j].v - DOT(rA_local[i], rB_local[j]);
                    fp u2 = a2 * r2;
                    fp vij = exp(-u2);
                    fp fs = 2.0 * vij;

                    THREE_VECTOR d;
                    d.x = (fp)rA_local[i].x - (fp)rB_local[j].x;
                    fp fxij = fs * d.x;
                    d.y = (fp)rA_local[i].y - (fp)rB_local[j].y;
                    fp fyij = fs * d.y;
                    d.z = (fp)rA_local[i].z - (fp)rB_local[j].z;
                    fp fzij = fs * d.z;

                    fv_v += (double)((fp)qB_local[j] * vij);
                    fv_x += (double)((fp)qB_local[j] * fxij);
                    fv_y += (double)((fp)qB_local[j] * fyij);
                    fv_z += (double)((fp)qB_local[j] * fzij);
                }

                fA[i].v += fv_v;
                fA[i].x += fv_x;
                fA[i].y += fv_y;
                fA[i].z += fv_z;
            }
        }
    }

    time4 = get_time();
    time5 = get_time();
    time6 = get_time();

    printf("Time spent in different stages of GPU_CUDA KERNEL:\n");

    printf("%15.12f s, %15.12f % : GPU: SET DEVICE / DRIVER INIT\n",   (float)(time1-time0) / 1000000, (float)(time1-time0) / (float)(time6-time0) * 100);
    printf("%15.12f s, %15.12f % : GPU MEM: ALO\n",                    (float)(time2-time1) / 1000000, (float)(time2-time1) / (float)(time6-time0) * 100);
    printf("%15.12f s, %15.12f % : GPU MEM: COPY IN\n",                (float)(time3-time2) / 1000000, (float)(time3-time2) / (float)(time6-time0) * 100);

    printf("%15.12f s, %15.12f % : GPU: KERNEL\n",                     (float)(time4-time3) / 1000000, (float)(time4-time3) / (float)(time6-time0) * 100);

    printf("%15.12f s, %15.12f % : GPU MEM: COPY OUT\n",               (float)(time5-time4) / 1000000, (float)(time5-time4) / (float)(time6-time0) * 100);
    printf("%15.12f s, %15.12f % : GPU MEM: FRE\n",                    (float)(time6-time5) / 1000000, (float)(time6-time5) / (float)(time6-time0) * 100);

    printf("Total time:\n");
    printf("%.12f s\n",                                                 (float)(time6-time0) / 1000000);
}
